            if ((mask & (1 << i)) != 0) {
                value += 2 * c[i];
                for (int j = 0; j < N; j++) {
                    if ((mask & (1 << j)) != 0 && !compatible[i][j]) {
                        isClique = false;
                        break;
                    }
                }
            }
        }
        if (isClique) {
            // Store the subset and its value in a priority queue
            printf("%d", value);
        }
    }
