#include <iostream>
#include <queue>
#include <vector>
using namespace std;

#define MAX_N 10000
#define MAX_M 20000
#define MAX_K 50

int T, N, M, K;
int c[MAX_N];
int ui[MAX_M], vi[MAX_M];
bool compatible[MAX_N][MAX_N];

void solve() {
    cin >> N >> M >> K;
    for (int i = 0; i < N; i++) {
        cin >> c[i];
    }
    for (int i = 0; i < M; i++) {
        cin >> ui[i] >> vi[i];
        compatible[ui[i]][vi[i]] = true;
        compatible[vi[i]][ui[i]] = true;
    }
    // Generate all possible subsets and check if they form a clique
    priority_queue<pair<int, vector<int>>> pq;
    for (int mask = 1; mask < (1 << N); mask++) {
        int value = 0;
        vector<int> subset;
        bool isClique = true;
        for (int i = 0; i < N; i++) {
            if ((mask & (1 << i)) != 0) {
                value += 2 * c[i];
                subset.push_back(i);
                for (int j = 0; j < N; j++) {
                    if ((mask & (1 << j)) != 0 && !compatible[i][j]) {
                        isClique = false;
                        break;
                    }
                }
            }
        }
        if (isClique) {
            pq.push({value, subset});
        }
    }
    // Output the K subsets with the highest values
    for (int i = 0; i < K; i++) {
        if (pq.empty()) break;
        auto subset = pq.top().second;
        pq.pop();
        for (int j = 0; j < subset.size(); j++) {
            cout << subset[j] << " ";
        }
        cout << endl;
    }
    cout << endl;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

