import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.PriorityQueue;
import java.util.StringTokenizer;
import java.util.Vector;

public class Main {
    static final int MAX_N = 10000;
    static final int MAX_M = 20000;
    static final int MAX_K = 50;

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            int[] c = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) {
                c[i] = Integer.parseInt(st.nextToken());
            }
            boolean[][] compatible = new boolean[N][N];
            for (int i = 0; i < M; i++) {
                st = new StringTokenizer(br.readLine());
                int ui = Integer.parseInt(st.nextToken());
                int vi = Integer.parseInt(st.nextToken());
                compatible[ui][vi] = true;
                compatible[vi][ui] = true;
            }
            // Generate all possible subsets and check if they form a clique
            PriorityQueue<Pair> pq = new PriorityQueue<>((a, b) -> b.value - a.value);
            for (int mask = 1; mask < (1 << N); mask++) {
                int value = 0;
                Vector<Integer> subset = new Vector<>();
                boolean isClique = true;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        value += 2 * c[i];
                        subset.add(i);
                        for (int j = 0; j < N; j++) {
                            if ((mask & (1 << j)) != 0 && !compatible[i][j]) {
                                isClique = false;
                                break;
                            }
                        }
                    }
                }
                if (isClique) {
                    pq.add(new Pair(value, subset));
                }
            }
            // Output the K subsets with the highest values
            for (int i = 0; i < K; i++) {
                if (pq.isEmpty()) break;
                Vector<Integer> subset = pq.poll().subset;
                for (int j = 0; j < subset.size(); j++) {
                    System.out.print(subset.get(j) + " ");
                }
                System.out.println();
            }
            System.out.println();
        }
    }

    static class Pair {
        int value;
        Vector<Integer> subset;

        public Pair(int value, Vector<Integer> subset) {
            this.value = value;
            this.subset = subset;
        }
    }
}

